// File: crypto_demo.dart
// Run: dart pub add crypto encrypt  &&  dart crypto_demo.dart
import 'dart:convert';
import 'package:crypto/crypto.dart';
import 'package:encrypt/encrypt.dart';

void main() {
  const message = 'my card is 4111-1111-1111-1111';

  // --- ENCODING (Base64) — reversible, no key, not security ---
  final b64 = base64Encode(utf8.encode(message));
  print('Base64 encoded : $b64');
  print('  decode back  : ${utf8.decode(base64Decode(b64))}');
  print('  ↑ ANYONE can do this. Not secret.\n');

  // --- HASHING (SHA-256) — one-way, deterministic ---
  final digest = sha256.convert(utf8.encode(message)).toString();
  print('SHA-256 hash   : $digest');
  print('  same length regardless of input;');
  print('  cannot be reversed back to the message.');
  print('  Good for: integrity checks. BAD for password storage.\n');

  // --- ENCRYPTION (AES-256 in GCM mode) — needs a key ---
  final key = Key.fromSecureRandom(32);
  final iv  = IV.fromSecureRandom(12);         // "initialization vector"
  final enc = Encrypter(AES(key, mode: AESMode.gcm));
  final ct  = enc.encrypt(message, iv: iv);

  print('AES-GCM cipher : ${ct.base64}');
  print('  needs the KEY to decrypt: ${enc.decrypt(ct, iv: iv)}');
  print('  Without the key, the ciphertext is useless.');
}

// Typical output:
// Base64 encoded : bXkgY2FyZCBpcyA0MTExLTExMTEtMTExMS0xMTEx
//   decode back  : my card is 4111-1111-1111-1111
//   ↑ ANYONE can do this. Not secret.
// SHA-256 hash   : 8f2a54b5...   (64 hex chars)
//   same length regardless of input;
//   cannot be reversed back to the message.
//   Good for: integrity checks. BAD for password storage.
// AES-GCM cipher : xJ7L8...   (random-looking bytes)
//   needs the KEY to decrypt: my card is 4111-1111-1111-1111
//   Without the key, the ciphertext is useless.
